@app.route('/mfa/setup', methods=['POST'])
def setup_mfa():
    """Initialize MFA setup - generates secret and QR code."""
    if 'user_id' not in session:
        return jsonify({'error': 'Authentication required'}), 401

    user_id = session['user_id']
    user = users_db.get(user_id)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled. Disable it first to reconfigure.'}), 409

    # Generate new TOTP secret
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")

    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode('utf-8')

    # Store the pending secret in session (not yet confirmed)
    session['pending_mfa_secret'] = secret

    return jsonify({
        'message': 'MFA setup initiated. Scan the QR code and verify with a token.',
        'secret': secret,
        'qr_code': f'data:image/png;base64,{qr_base64}',
        'provisioning_uri': provisioning_uri
    }), 200


@app.route('/mfa/enable', methods=['POST'])
def enable_mfa():
    """Confirm and enable MFA by verifying the first token."""
    if 'user_id' not in session:
        return jsonify({'error': 'Authentication required'}), 401

    user_id = session['user_id']
    user = users_db.get(user_id)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled'}), 409

    pending_secret = session.get('pending_mfa_secret')
    if not pending_secret:
        return jsonify({'error': 'Please initiate MFA setup first via /mfa/setup'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    token = data.get('token', '').strip()
    if not token:
        return jsonify({'error': 'Verification token is required'}), 400

    # Verify the token against the pending secret
    totp = pyotp.TOTP(pending_secret)
    if not totp.verify(token, valid_window=1):
        return jsonify({'error': 'Invalid token. Please try again.'}), 401

    # Generate backup codes
    backup_codes_plain = [secrets.token_hex(4).upper() for _ in range(10)]
    backup_codes_hashed = [generate_password_hash(code) for code in backup_codes_plain]

    # Enable MFA
    user['mfa_enabled'] = True
    user['mfa_secret'] = pending_secret
    user['mfa_backup_codes'] = backup_codes_hashed
    user['updated_at'] = datetime.utcnow().isoformat()

    session.pop('pending_mfa_secret', None)
    session['mfa_verified'] = True

    return jsonify({
        'message': 'MFA enabled successfully',
        'backup_codes': backup_codes_plain,
        'warning': 'Store these backup codes safely. They will not be shown again.'
    }), 200


@app.route('/mfa/disable', methods=['POST'])
def disable_mfa():
    """Disable MFA for the current user. Requires password confirmation."""
    if 'user_id' not in session:
        return jsonify({'error': 'Authentication required'}), 401

    if not session.get('mfa_verified'):
        return jsonify({'error': 'MFA verification required'}), 403

    user_id = session['user_id']
    user = users_db.get(user_id)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not enabled'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    password = data.get('password', '')
    if not password:
        return jsonify({'error': 'Password confirmation is required'}), 400

    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid password'}), 401

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['updated_at'] = datetime.utcnow().isoformat()

    return jsonify({'message': 'MFA disabled successfully'}), 200


