@app.route('/reset-mfa', methods=['POST'])
def reset_mfa_request():
    """
    Account recovery: Request MFA reset via email.
    Sends a reset link to the registered email address.
    The reset link will disable MFA, allowing login with just password.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Find user by email
    target_user = None
    for uid, user in users_db.items():
        if user['email'] == email:
            target_user = user
            break

    # Always return success to prevent email enumeration
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to the registered email address.'
    )

    if not target_user:
        return jsonify({'message': success_message}), 200

    if not target_user['mfa_enabled']:
        return jsonify({'message': success_message}), 200

    # Rate limiting check: don't allow more than one reset request per 5 minutes
    for token_id, token_data in list(mfa_reset_tokens.items()):
        if (token_data['user_id'] == target_user['id'] and
                token_data['created_at'] > datetime.utcnow() - timedelta(minutes=5) and
                not token_data['used']):
            return jsonify({'message': success_message}), 200

    # Generate a secure reset token
    reset_token = secrets.token_urlsafe(48)
    token_id = secrets.token_hex(16)

    mfa_reset_tokens[token_id] = {
        'token': reset_token,
        'user_id': target_user['id'],
        'email': email,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(hours=1),
        'used': False,
        'ip_address': request.remote_addr
    }

    # Build the reset link
    reset_link = url_for(
        'confirm_mfa_reset',
        token_id=token_id,
        token=reset_token,
        _external=True
    )

    # Send email with reset link
    email_subject = 'MFA Reset Request - Account Recovery'
    email_body = f"""Hello {target_user.get('name', 'User')},

We received a request to reset the Multi-Factor Authentication (MFA) on your account.

If you made this request, click the link below to disable MFA on your account:

{reset_link}

This link will expire in 1 hour.

After clicking the link, MFA will be disabled on your account, and you will be able
to log in using only your email and password. We strongly recommend re-enabling MFA
after you regain access to your account.

If you did NOT request this reset, please ignore this email and ensure your account
password is secure. Your MFA settings will remain unchanged.

Security Notice:
- This request was made from IP: {request.remote_addr}
- Request time: {datetime.utcnow().isoformat()} UTC

Best regards,
MFA Management System Security Team
"""

    send_email(email, email_subject, email_body)

    return jsonify({'message': success_message}), 200


@app.route('/reset-mfa/confirm', methods=['GET'])
def confirm_mfa_reset():
    """
    Confirm MFA reset via the link sent to email.
    Disables MFA on the account, allowing password-only login.
    """
    token_id = request.args.get('token_id', '').strip()
    token = request.args.get('token', '').strip()

    if not token_id or not token:
        return jsonify({'error': 'Invalid reset link'}), 400

    # Look up the reset token
    token_data = mfa_reset_tokens.get(token_id)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset link'}), 400

    # Verify token matches
    if not secrets.compare_digest(token_data['token'], token):
        return jsonify({'error': 'Invalid reset link'}), 400

    # Check if already used
    if token_data['used']:
        return jsonify({'error': 'This reset link has already been used'}), 400

    # Check expiration
    if datetime.utcnow() > token_data['expires_at']:
        return jsonify({'error': 'This reset link has expired. Please request a new one.'}), 400

    # Find the user
    user = users_db.get(token_data['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['updated_at'] = datetime.utcnow().isoformat()

    # Mark token as used
    token_data['used'] = True
    token_data['used_at'] = datetime.utcnow().isoformat()

    # Invalidate all other pending reset tokens for this user
    for tid, tdata in mfa_reset_tokens.items():
        if tdata['user_id'] == user['id'] and tid != token_id and not tdata['used']:
            tdata['used'] = True
            tdata['used_at'] = datetime.utcnow().isoformat()

    # Send confirmation email
    send_email(
        user['email'],
        'MFA Has Been Disabled - Account Recovery',
        f"""Hello {user.get('name', 'User')},

MFA has been successfully disabled on your account as requested.

You can now log in using only your email and password.

We strongly recommend re-enabling MFA as soon as possible to keep your account secure.

If you did NOT request this change, please immediately:
1. Change your password
2. Re-enable MFA
3. Contact our support team

Security Notice:
- MFA was disabled at: {datetime.utcnow().isoformat()} UTC
- Request originated from IP: {token_data.get('ip_address', 'unknown')}

Best regards,
MFA Management System Security Team
"""
    )

    return jsonify({
        'message': 'MFA has been successfully disabled on your account.',
        'next_steps': [
            'You can now log in with just your email and password.',
            'We strongly recommend re-enabling MFA after logging in.',
            'Go to /mfa/setup to set up MFA again.'
        ]
    }), 200


